border:1px solid grey;
border-radius:20px;
color:grey;
padding:5px 10px;
display:inline-block;
font-size:0.9rem;
margin:10px 0;
`
const Div = styled.div `
display:flex;
`


export default function Message () {

	return (
		<Div>
			<TheMessage>Hey I like you</TheMessage>
		</Div>
	)
}
